1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	const DEDUCTIBLE = 100;
32	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
33	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
34	const CAP_MULTIPLIER = 2;
35	
36	type Item = { type: string; cursed?: boolean; enchantment?: number };
37	type QuoteStep = { op: "quote"; items: Array<Item> };
38	type Damage = { itemType: string; amount: number };
39	type ClaimStep = { op: "claim"; policy: number; incident: { cause: string; damages: Array<Damage> } };
40	type Step = QuoteStep | ClaimStep;
41	type Customer = { yearsWithMHPCO: number };
42	type Scenario = { customer: Customer; steps: Array<Step> };
43	type Policy = { items: Array<Item>; remainingCap: number };
44	
45	const sum = (xs: number[]): number => xs.reduce((a, b) => a + b, 0);
46	
47	const countByType = (items: Item[]): Record<string, number> => {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) {
50	    counts[item.type] = (counts[item.type] ?? 0) + 1;
51	  }
52	  return counts;
53	};
54	
55	const qualifiesForBlockDiscount = (type: string, count: number): boolean =>
56	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
57	
58	const subtotalForType = (type: string, count: number): number =>
59	  qualifiesForBlockDiscount(type, count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
60	
61	const policyBaseFor = (items: Item[]): number =>
62	  sum(Object.entries(countByType(items)).map(([type, count]) => subtotalForType(type, count)));
63	
64	const isHighlyEnchanted = (item: Item): boolean =>
65	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
66	
67	const surchargeRate = (item: Item): number =>
68	  (item.cursed ? CURSED_SURCHARGE_RATE : 0) +
69	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
70	
71	const itemSurcharge = (item: Item): number => BASE_PREMIUMS[item.type] * surchargeRate(item);
72	
73	const itemSurchargesFor = (items: Item[]): number => sum(items.map(itemSurcharge));
74	
75	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
76	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
77	
78	const loyaltyDiscountFor = (policyBase: number, customer: Customer): number =>
79	  qualifiesForLoyaltyDiscount(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
80	
81	const firstInsuranceSurchargeFor = (policyBase: number): number =>
82	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
83	
84	const isFollowUpQuote = (quoteIndex: number): boolean => quoteIndex > 0;
85	
86	const followUpDiscountFor = (policyBase: number, quoteIndex: number): number =>
87	  isFollowUpQuote(quoteIndex) ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
88	
89	const quotePremium = ({ items }: QuoteStep, customer: Customer, quoteIndex: number): number => {
90	  const policyBase = policyBaseFor(items);
91	  const itemSurchargesTotal = itemSurchargesFor(items);
92	  const firstInsuranceSurcharge = firstInsuranceSurchargeFor(policyBase);
93	  const loyaltyDiscount = loyaltyDiscountFor(policyBase, customer);
94	  const followUpDiscount = followUpDiscountFor(policyBase, quoteIndex);
95	  return Math.ceil(policyBase + itemSurchargesTotal + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
96	};
97	
98	const insuranceSumFor = (items: Item[]): number =>
99	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
100	
101	const payoutRateFor = (item: Item): number =>
102	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD ? HIGH_ENCHANTMENT_PAYOUT_RATE : 1;
103	
104	const payoutForDamage = (damage: Damage, policy: Policy): number => {
105	  const item = policy.items.find((i) => i.type === damage.itemType)!;
106	  return Math.floor(damage.amount * payoutRateFor(item) - DEDUCTIBLE);
107	};
108	
109	const processClaim = (step: ClaimStep, policies: Policy[]): { payout: number; remainingCap: number } => {
110	  const policy = policies[step.policy];
111	  const payout = sum(step.incident.damages.map((d) => payoutForDamage(d, policy)));
112	  policy.remainingCap -= payout;
113	  return { payout, remainingCap: policy.remainingCap };
114	};
115	
116	const newPolicy = (items: Item[]): Policy =>
117	  ({ items, remainingCap: insuranceSumFor(items) * CAP_MULTIPLIER });
118	
119	const processQuote = (step: QuoteStep, customer: Customer, policies: Policy[]): { premium: number } => {
120	  const premium = quotePremium(step, customer, policies.length);
121	  policies.push(newPolicy(step.items));
122	  return { premium };
123	};
124	
125	export const runScenario = (input: unknown): unknown => {
126	  const scenario = input as Scenario;
127	  const policies: Policy[] = [];
128	  const results = scenario.steps.map((step) =>
129	    step.op === "quote"
130	      ? processQuote(step, scenario.customer, policies)
131	      : processClaim(step, policies)
132	  );
133	  return { results };
134	};
